import React, { useState } from 'react';
import { View, Text, Button } from 'react-native';
import { InAppPurchase, DigitalWallet } from 'react-native-payment-gateway';

const PaymentModule = () => {
  const [purchaseStatus, setPurchaseStatus] = useState('');
  const [walletStatus, setWalletStatus] = useState('');

  const handleInAppPurchase = async () => {
    try {
      const result = await InAppPurchase.purchase('product_id');
      if (result.status === 'success') {
        setPurchaseStatus('Payment successful!');
      } else {
        setPurchaseStatus('Payment failed.');
      }
    } catch (error) {
      setPurchaseStatus(`Error: ${error.message}`);
    }
  };

  const handleDigitalWalletTransaction = async () => {
    try {
      const result = await DigitalWallet.processTransaction('wallet_id', 'amount');
      if (result.status === 'success') {
        setWalletStatus('Transaction successful!');
      } else {
        setWalletStatus('Transaction failed.');
      }
    } catch (error) {
      setWalletStatus(`Error: ${error.message}`);
    }
  };

  return (
    <View>
      <Text>In-App Purchase Status: {purchaseStatus}</Text>
      <Button title="Process In-App Purchase" onPress={handleInAppPurchase} />
      
      <Text>Digital Wallet Transaction Status: {walletStatus}</Text>
      <Button title="Process Digital Wallet Transaction" onPress={handleDigitalWalletTransaction} />
    </View>
  );
};

export default PaymentModule;